import { Component, OnInit } from '@angular/core';
import { RagService, QueryResponse } from '../../services/rag.service';

interface Message {
  type: 'user' | 'assistant';
  content: string;
  sources?: Array<{
    file_path: string;
    start_line: number;
    end_line: number;
    chunk_index: number;
  }>;
  timestamp: Date;
}

@Component({
  selector: 'app-chat',
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.css']
})
export class ChatComponent implements OnInit {
  messages: Message[] = [];
  inputMessage = '';
  isLoading = false;
  collectionCount = 0;

  constructor(private ragService: RagService) { }

  ngOnInit() {
    this.loadCollectionStats();
  }

  sendMessage() {
    if (!this.inputMessage.trim()) {
      return;
    }

    if (this.collectionCount === 0) {
      alert('Please index a repository first using the "Index Repository" tab');
      return;
    }

    // Add user message
    const userMessage: Message = {
      type: 'user',
      content: this.inputMessage,
      timestamp: new Date()
    };
    this.messages.push(userMessage);

    // Clear input
    const query = this.inputMessage;
    this.inputMessage = '';
    this.isLoading = true;

    // Query RAG system
    this.ragService.queryCodebase(query, 5).subscribe(
      (response: QueryResponse) => {
        const assistantMessage: Message = {
          type: 'assistant',
          content: response.answer,
          sources: response.sources,
          timestamp: new Date()
        };
        this.messages.push(assistantMessage);
        this.isLoading = false;
      },
      (error) => {
        const errorMessage: Message = {
          type: 'assistant',
          content: `Error: ${error.error?.detail || 'Failed to process query. Make sure Ollama is running.'}`,
          timestamp: new Date()
        };
        this.messages.push(errorMessage);
        this.isLoading = false;
      }
    );
  }

  loadCollectionStats() {
    this.ragService.getCollectionStats().subscribe(
      (stats) => {
        this.collectionCount = stats.count;
      },
      (error) => {
        console.error('Error loading collection stats:', error);
      }
    );
  }

  getSourceLabel(source: any): string {
    return `${source.file_path} (Lines ${source.start_line}-${source.end_line})`;
  }
}
<div class="chat-container">
  <div class="collection-info" *ngIf="collectionCount > 0">
    <span class="badge">{{ collectionCount }} chunks indexed</span>
  </div>

  <div class="messages">
    <div *ngFor="let message of messages" [class]="'message ' + message.type">
      <div class="message-content">
        <div class="text">{{ message.content }}</div>

        <div *ngIf="message.sources && message.sources.length > 0" class="sources">
          <details>
            <summary>📄 Sources ({{ message.sources.length }})</summary>
            <ul>
              <li *ngFor="let source of message.sources" class="source-item">
                <strong>{{ source.file_path }}</strong>
                <br>
                <small>Lines {{ source.start_line }}-{{ source.end_line }}</small>
              </li>
            </ul>
          </details>
        </div>
      </div>
      <span class="timestamp">{{ message.timestamp | date:'short' }}</span>
    </div>

    <div *ngIf="isLoading" class="message assistant">
      <div class="message-content">
        <div class="loading">
          <span></span><span></span><span></span>
        </div>
      </div>
    </div>
  </div>

  <div class="input-area">
    <input 
      type="text" 
      [(ngModel)]="inputMessage" 
      (keyup.enter)="sendMessage()"
      placeholder="Ask about your code... (e.g., 'How does the authentication work?')"
      [disabled]="isLoading"
      class="input-field">
    <button 
      (click)="sendMessage()" 
      [disabled]="isLoading || !inputMessage.trim()"
      class="send-button">
      {{ isLoading ? 'Sending...' : 'Send' }}
    </button>
  </div>
</div>
